(window.webpackJsonp=window.webpackJsonp||[]).push([[8],{635:function(r,n){r.exports='\x3c!-- \r\ntitle: 05-数组与指针\r\nsort: \r\n--\x3e \r\n## C的指针\r\n\r\n> 指针是一个值为内存地址的变量。\r\n>\r\n> `prt = &i //把i的地址赋给指针变量ptr`\r\n>\r\n> 间接运算符`*`找出指针指向的值\r\n\r\n### 声明一个指针\r\n\r\n```c\r\nint *pi;\r\n// int 表示指向int *表示指针 pi为变量名\r\n// 赋值\r\nint *i;\r\ni=(int*)404;\r\nprintf("%d",i);\r\n```\r\n\r\n### 函数间通信\r\n\r\n```c\r\nvoid interchange(int *, int *);\r\ninterchange(&x, &y)\t\t// 使用&传入xy的地址\r\n// 函数修改变量只后无需return\r\n```\r\n\r\n## 数组\r\n\r\n> 不允许把数组作为单元赋给另一个数组。\r\n>\r\n> arr[-1]被允许，向下占用空间、\r\n>\r\n> C99后支持边长数组\r\n>\r\n> 多维数组可省略内部的{}\r\n\r\n#### 数组的大小\r\n\r\n`sizeof array / sizeof array[0]`\r\n\r\n### 指定初始化器\r\n\r\n`int arr[4] = {2, [0] = 1, [3] = 4, 3}`\r\n\r\n`{1,2,3,4}`\r\n\r\n### 数组名\r\n\r\n> 数组名是该数组首元素的地址\r\n> \r\n> `array = &array[0]`\r\n```c\r\nchar ch[] = {1,2,3};\r\nprintf("%p\\n",ch);\r\nprintf("%p\\n",&ch[1]);\r\n// 2a4fdec5\r\n// 2a4fdec6\r\n```\r\n\r\n### 数组指针\r\n\r\n```c\r\nchar ch[]={0,1,2,3,4};\r\n*ch == ch[0];\r\n*ch+2 == ch[2];\r\n// &ch == ch;\r\n\r\n```\r\n\r\n\r\n## 指针\r\n\r\n### 指针操作\r\n\r\n> 使用`const`防止数组被错误修改\r\n\r\n1. 赋值\r\n   ```c\r\n   array = array1;\r\n   array = &array[2];\r\n   i = *(array + 4)\r\n   ```\r\n   \r\n2. 解引用`*`\r\n\r\n3. 取址`&`\r\n\r\n4. 指针转换\r\n\r\n   ```c\r\n   char data[] =\r\n   {\r\n       0x00,0x02,0x03,0x04,0x05,0x06,0x07\r\n   };\r\n   // 将char* 转为 int*\r\nint *p = (int*)&data;\r\n   ```\r\n   \r\n5. 取值\r\n\r\n   ```c\r\n   struct data\r\n   {\r\n       int a;\r\n       int b;\r\n       int c;\r\n   };\r\n   \r\n   struct data s;\r\n   \r\n   s.a=1;\r\n   s.b=2;\r\n   s.c=3;\r\n   \r\n   struct data* px = &s;\r\n   \r\n   px->a = 10;\r\n   \r\n   printf("%d",px->a);\r\n   ```\r\n6. const\r\n   ```c\r\n   int i = 404;\r\n   int * ptr;\r\n   const int * ptr = &i;\r\n   // ptr可修改, i可修改, 不能通过*ptr=400 来修改i\r\n   int const * ptr = &i;\r\n   // 同上\r\n   int * const ptr;\r\n   // ptr 不可以指向别的地址\r\n   ```\r\n### 多维数组\r\n\r\n```c\r\narray+2     // 二维数组的第三个一维数组\r\n*(array+2)  // 二维数组的第三个一维数组的第一个元素的地址\r\n*(array+2) + 1    // 二维数组的...第二个元素的地址\r\n*(*arry+2) + 1)   // ...元素的值\r\n```\r\n\r\n### 复合自面量\r\n\r\n`int *i = (int [3]) { 1,2,3 }`\r\n\r\n## 结构体\r\n\r\n> 按照数据从大到小书写\r\n\r\n```c\r\n#pragma pack(4) // 设置对齐字节数\r\n// 默认为8\r\nstruct s1\r\n{\r\n    char name[40];\r\n    bool sex;\r\n    unsigned char age; \r\n};\r\n#pragma pack()\r\n```\r\n\r\n### 结构体指针\r\n\r\n```c\r\nstruct student\r\n{\r\n\tchar name[40];  \r\n\tint age;      \r\n\tint score;    \r\n};\r\n// 结构体数组\r\nstruct student arr[3]=\r\n{\r\n\t{"张三",18,80 },\r\n\t{"李四",19,60 },\r\n\t{"王五",20,70 }\r\n};\r\n// 结构体指针\r\nstruct student * p = &arr[0];\r\np->score=75;\r\nprintf("%d",arr[0].score);\r\n```\r\n\r\n'}}]);